sql:
SELECT interaction_type, interaction_strength
FROM gene_interactions
WHERE gene_id_1 = 1 AND gene_id_2 = 2;

external_knowledge:
- "species they're found in" refers to the species in which the genes are expressed;
- "how they're influenced" refers to whether the genes are upregulated or downregulated;
- "extent of their expression changes" refers to the fold change in gene expression;
- "food these species typically eat" refers to the diet of the species.

sql:
SELECT COUNT(DISTINCT gene_id)
FROM gene_aliases
WHERE alias_source = 'NCBI';
